var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"POLICE_EXTRA_NULL_NULL","text":{"KOREA":"경정님? 폴른 호크라는 데에서 편지가 왔던데……","JPN":"警視？　フォーレン・ホークというところから手紙が来ていますが……","ENG":"Major? You received a letter from a place called \\"Fallen Hawk\\"...","TWN":"警正？收到一個叫作墮落之鷹的地方來信……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"POLICE_EXTRA_NULL_NULL","text":{"KOREA":"뭐야? 현장 나가셨나? 경위님도 안 계시네.","JPN":"あれ？　現場かな？　警部補もいない。","ENG":"Huh? I guess she's out? I don't see the lieutenant either.","TWN":"人呢？去現場啦？姜警官也不在？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POLICE_EXTRA_NULL_NULL","text":{"KOREA":"책상 위에다 놓고 가야 하나…… 이거 괜히 또 한소리 듣는 거 아닌가 몰라.","JPN":"机の上においていくか……？　また怒られるかもしれないしな。","ENG":"Do I just leave it on her desk? I don't want to get another earful from her...","TWN":"要放在桌子上嗎……不知道會不會又惹罵？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>간만에 인사드리는군요, 형사님. 의뢰하셨던 실종자 탐색에 대해 전해 드릴 소식이 있습니다.</color>","JPN":"<color=#ffd34c>ご無沙汰しております、刑事さん。依頼してくださった失踪者の探索についてお知らせすることがあります。</color>","ENG":"<color=#ffd34c>Hello, Detective. Many moons have passed since we last talked. I am writing this letter to update you about the search for the missing person that you requested.</color>","TWN":"<color=#ffd34c>警官，好久不見。關於之前您委託尋找失蹤人士一事，有消息要告訴您。</color>"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>결론부터 말씀드리죠. 언니 분은 찾았지만 형사님과 만나길 원치 않으시더군요.</color>","JPN":"<color=#ffd34c>結論からお話いたしましょう。お姉さんは見つかりましたが、刑事さんとは会いたくないとおっしゃっていました。</color>","ENG":"<color=#ffd34c>Regarding your sister, I have found her, but it seems that she does not want to meet with you.</color>","TWN":"<color=#ffd34c>先說結論吧，我已經找到您的姊姊，但她不想見您。</color>"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그래서 대신 서신을 받아 왔습니다. 동봉해 두었으니 확인해 보시죠.</color>","JPN":"<color=#ffd34c>それで代わりに手紙をもらってきました。同封しましたのでご確認を。</color>","ENG":"<color=#ffd34c>So instead, I received a letter. I have enclosed the letter as well, so that you can read it.</color>","TWN":"<color=#ffd34c>不過她有寫封信給您，信已經隨此信附上，請您查閱。</color>"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>혹여 다른 의뢰가 있으시면 언제든 연락 주시길.</color>","JPN":"<color=#ffd34c>もし他にご依頼がございましたら、いつでもご連絡ください。</color>","ENG":"<color=#ffd34c>If there is anything else I can do for you, please contact me at your earliest convenience.</color>","TWN":"<color=#ffd34c>若有其他委託，請隨時聯繫我。</color>"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"유치원 이후로 처음 쓰는 편지인데 너한테 잘 전해질지 모르겠네.","JPN":"幼稚園以来、初めて手紙を書くけどちゃんと伝わるかな。","ENG":"I haven't written a letter since I was in kindergarten. I hope this reaches you, though.","TWN":"自從幼稚園後，這還是我第一次寫信，不知道能不能順利交到你手裡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 이 편지가 가짜라고 의심할지도 모르겠어.","JPN":"もしかしたらこの手紙は偽物だと疑うかもしれないね。","ENG":"Or maybe, you suspect that this letter is fake.","TWN":"說不定你會懷疑這封信是假的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 이것만은 장담할게. 나는 네가 믿는 대로 멀쩡하게 살아 있어.","JPN":"でもこれだけは確かだよ。私はあなたが信じてるとおり、ちゃんと生きてる。","ENG":"But let me assure you. I'm alive and well.","TWN":"不過唯獨這件事我可以保證，就是我還活得好好的，正如你所相信的那樣。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리, 기회는 지금뿐이다. 어서 여길 빠져나가.","JPN":"カスカベ、チャンスは今しかない。早くここから脱出しろ。","ENG":"Yuri. Now's your chance. Get out of here, now!","TWN":"李悠麗，趁現在，快離開這裡。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 대장은 그 상태로 뭘 어쩌려고?","JPN":"は？　隊長はその身体でどうするつもりだ？","ENG":"What? Then what about you?","TWN":"什麼？隊長你傷得那麼重還想做什麼？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"할일은 마치고 가야지. 처음 얘기했던 집결지에서 보자.","JPN":"仕事は終えないとな。最初に話した集結地で会おう。","ENG":"Someone's gotta finish the job. I'll meet you back at the rendezvous point.","TWN":"當然是做完該做的事再走，我們在一開始說好的集合地點見！"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……알겠어, 대장. 기다리고 있을게.","JPN":"……わかった、隊長。待ってるから。","ENG":"...Okay, Captain. I'll be waiting for you.","TWN":"……好，隊長，我等你。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"윽……! 기다려!","JPN":"うっ……！　ちょっと！","ENG":"Ngh...! Hold it!","TWN":"唔……！等等！"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":" 누구 맘대로 도망치겠다는 거야?!","JPN":" 何を勝手に逃げてるの！？","ENG":"  Where do you think you're going?!","TWN":" 誰准你逃走的？！"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"고마워, 이유미 경정. 네 덕분에 확실해졌어.","JPN":"ありがとう、カスカベ・ユミ警視。おかげで確信できた。","ENG":"Thank you, Major Lee Yumi. Everything's crystal clear, all thanks to you.","TWN":"謝謝你，李悠美警正。托你的福，讓我確定一件事。"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};